from langflow.custom import CustomComponent
from langflow.schema import Data
import json

class AudioRetrievalService(CustomComponent):
    display_name = "Audio Retrieval Service"
    description = "Searches audio datasets using semantic tag matches."

    def build_config(self):
        return {
            "topic_name": {"display_name": "Topic Name", "type": "str"},
            "dataset": {
                "display_name": "Audio Records (JSON)",
                "type": "str",
                "value": '[
                    {"id": 1, "topicId": "birth-shree-ram", "title": "Divine Incarnation of Lord Ram", "audioUrl": "https://example.com/audio/ram-birth.mp3", "tags": ["ram", "birth", "divine"]},
                    {"id": 2, "topicId": "childhood-krishna", "title": "Bala Leela of Krishna", "audioUrl": "https://example.com/audio/krishna-child.mp3", "tags": ["krishna", "childhood", "leela"]}
                ]'
            }
        }

    def build(self, topic_name: str, dataset: str) -> Data:
        records = json.loads(dataset)
        results = []
        for record in records:
            if topic_name.lower() in record['title'].lower() or topic_name.lower() in record['topicId'].lower():
                results.append(record)

        self.status = results
        return Data(value=results)

